console.log(`Preparing to insert ${FACILITIES.length} global facilities...`);

let inserted = 0;
let skipped = 0;

for (const f of FACILITIES) {
  // Check if facility already exists (by name + country)
  const [existing] = await conn.execute(
    "SELECT id FROM facilities WHERE name = ? AND country = ? LIMIT 1",
    [f.name, f.country]
  );
  if (existing.length > 0) {
    console.log(`  SKIP (exists): ${f.name} (${f.country})`);
    skipped++;
    continue;
  }

  await conn.execute(
    `INSERT INTO facilities (
      name, type, country, region, city, latitude, longitude,
      description, operator, importance, threatLevel, status,
      primarySourceUrl, primarySourceName, primarySourceType, tags,
      verificationStatus
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    [
      f.name, f.type, f.country, f.region, f.city ?? null,
      f.latitude, f.longitude, f.description ?? null,
      f.operator ?? null, f.importance ?? 5, f.threatLevel ?? "low",
      f.status ?? "active", f.primarySourceUrl ?? null,
      f.primarySourceName ?? null, f.primarySourceType ?? "manual_entry",
      JSON.stringify(f.tags ?? []),
      "verified"
    ]
  );
  console.log(`  INSERT: ${f.name} (${f.region})`);
  inserted++;
}

console.log(`\nDone. Inserted: ${inserted}, Skipped (already exists): ${skipped}`);
await conn.end();
